mapper.update:
/* TodoRepository.update */
UPDATE todo
SET
    todo_title = #{todoTitle},
    finished = #{finished},
    created_at = #{createdAt}
WHERE
    todo_id = #{todoId}

mapper.delete:
/* TodoRepository.delete */
DELETE FROM
    todo
WHERE
    todo_id = #{todoId}

mapper.select:
/* TodoRepository.countByFinished */
SELECT
    COUNT(*)
FROM
    todo
WHERE
    user_id = #{userId}
AND
    finished = #{finished}
